{
  "domain_analysis": {
    "business_context": "Refactoring from shipment-level tracking to parcel-level tracking to detect partial delivery. Currently the system treats a multi-parcel shipment as a single unit with one tracking number and one status. The business needs granular visibility into each parcel's lifecycle to handle real-world scenarios: partial deliveries, individual parcel loss, and customer disputes referencing specific parcels.",
    "bounded_context": "Shipment Tracking & Delivery",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "An aggregate root representing a customer's order fulfillment unit. Contains one or more Parcels. Its status is DERIVED from the collective state of its Parcels — it no longer holds an independent lifecycle." },
      { "term": "Parcel", "definition": "An individually trackable physical package within a Shipment. Each Parcel has its own tracking number, its own lifecycle, and its own state machine. This is the new atomic unit of delivery." },
      { "term": "Parcel Tracking Number", "definition": "A unique identifier assigned to each Parcel enabling independent tracking through the logistics network. Distinct from the Shipment reference number." },
      { "term": "Shipment Reference", "definition": "The parent identifier that groups related Parcels. Used for customer-facing communication and billing. Not a tracking number — parcels are tracked individually." },
      { "term": "Partial Delivery", "definition": "A Shipment state where at least one Parcel has been delivered but at least one other Parcel has NOT reached a terminal state of Delivered. This is the core scenario the refactor enables." },
      { "term": "Terminal State", "definition": "A Parcel state from which no further forward transitions occur under normal operations: Delivered, Lost (confirmed), or Returned to Sender." },
      { "term": "Delivery Attempt", "definition": "A recorded event where a courier tried to deliver a Parcel. Failed attempts must be tracked with a reason code. Multiple attempts are standard before escalation." },
      { "term": "Parcel Exception", "definition": "Any event that diverts a Parcel from the happy path: damage detected, delivery failure, suspected loss, held at customs, etc." },
      { "term": "Dispute", "definition": "A customer-initiated claim that the recorded delivery state of one or more specific Parcels does not match physical reality (e.g., marked delivered but not received)." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every Parcel within a Shipment MUST have its own unique tracking number, independent of the Shipment reference.",
      "invariant": true,
      "invariant_justification": "Without a unique tracking number per parcel, the system cannot distinguish parcels in transit, which is the entire purpose of this refactor. A parcel without a tracking number is untrackable — the data is corrupt.",
      "testable_assertion": "Given a Shipment with N parcels, there must be exactly N distinct, non-null parcel tracking numbers."
    },
    {
      "id": "BR-2",
      "rule": "A Shipment MUST contain at least one Parcel. A Shipment with zero Parcels is invalid.",
      "invariant": true,
      "invariant_justification": "A Shipment is an aggregate of Parcels. An empty aggregate has no physical meaning — there is nothing to ship. Allowing zero parcels would corrupt downstream calculations (delivery percentage, billing).",
      "testable_assertion": "Any attempt to create or persist a Shipment with an empty Parcel list must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Shipment status MUST be derived from the aggregate of its Parcel statuses. It must never be set independently.",
      "invariant": true,
      "invariant_justification": "If Shipment status can diverge from Parcel reality, the system lies to the customer. The whole point of parcel-level tracking is that the Shipment status reflects ground truth. An independently-set shipment status is a data integrity violation.",
      "testable_assertion": "There is no public method or API to directly set Shipment status. Shipment status is always computed from Parcel states."
    },
    {
      "id": "BR-4",
      "rule": "Shipment derived status rules: CREATED (all parcels Created), IN_TRANSIT (any parcel picked up or in transit, none delivered), PARTIALLY_DELIVERED (at least one Delivered AND at least one not in a terminal state or in a non-Delivered terminal state), DELIVERED (all parcels Delivered), FAILED (all parcels in terminal states AND at least one is not Delivered — e.g., all Lost or Returned).",
      "invariant": true,
      "invariant_justification": "These derivation rules are the core business logic of partial delivery detection. If the mapping is wrong, customers see incorrect shipment status, operations cannot triage, and SLA calculations break.",
      "testable_assertion": "Given 5 parcels where 3 are Delivered, 1 is In Transit, and 1 is Lost, the Shipment status must be PARTIALLY_DELIVERED."
    },
    {
      "id": "BR-5",
      "rule": "Parcel state transitions must follow the defined state machine. Forward-only transitions under normal flow: Created → Picked Up → In Transit → Out for Delivery → Delivered. Exception branches: any active state → Damaged, In Transit → Lost (suspected), Out for Delivery → Delivery Failed, any non-terminal state → Returned to Sender.",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary state transitions (e.g., Delivered → In Transit) would corrupt tracking history, break audit trails, and misrepresent the physical reality of where a parcel is. The state machine encodes physical constraints of the logistics network.",
      "testable_assertion": "Attempting to transition a Parcel from Delivered to In Transit must throw a domain exception."
    },
    {
      "id": "BR-6",
      "rule": "A Parcel marked as Delivered MUST record: proof of delivery timestamp, GPS coordinates or location identifier, and recipient identifier (name or signature reference).",
      "invariant": true,
      "invariant_justification": "Without proof-of-delivery data, the system cannot defend against disputes. A Delivered status without evidence is an unverifiable claim. This data is required for dispute resolution and legal compliance.",
      "testable_assertion": "Transitioning a Parcel to Delivered without a proof-of-delivery record must be rejected by the domain."
    },
    {
      "id": "BR-7",
      "rule": "Each Parcel state transition MUST be recorded as an immutable event with timestamp, actor, location, and reason (for exceptions). History cannot be modified or deleted.",
      "invariant": true,
      "invariant_justification": "The tracking history is the audit trail. Modifying or deleting history events would undermine dispute resolution, regulatory compliance, and operational debugging. Immutability is a physical-world constraint — you cannot un-deliver a parcel.",
      "testable_assertion": "The parcel event log must be append-only. No update or delete operations exist on tracking events."
    },
    {
      "id": "BR-8",
      "rule": "A Dispute MUST reference one or more specific Parcels by tracking number, not just the Shipment. The system must not accept a dispute that does not identify which parcels are contested.",
      "invariant": true,
      "invariant_justification": "A dispute at the Shipment level is ambiguous — 'I didn't receive my shipment' when 3 of 5 parcels were delivered is meaningless without knowing which parcels are contested. Parcel-level disputes enable targeted investigation.",
      "testable_assertion": "Creating a Dispute without at least one Parcel tracking number must be rejected."
    },
    {
      "id": "BR-9",
      "rule": "Parcels within the same Shipment may travel on different routes and carriers. The system must not assume all Parcels in a Shipment share the same logistics path.",
      "invariant": false,
      "invariant_justification": "This is a logistics operational reality (oversized items ship separately, multi-warehouse fulfillment), but a business could choose to constrain all parcels to one carrier as a policy decision.",
      "testable_assertion": "Two Parcels in the same Shipment can have different carrier identifiers and independent tracking event streams."
    },
    {
      "id": "BR-10",
      "rule": "When a Parcel transitions to Lost (confirmed), the Shipment must emit a domain event (ParcelLostConfirmed) that downstream systems can react to (claims, replacement, customer notification).",
      "invariant": false,
      "invariant_justification": "The event-driven notification is a policy choice — the business could choose polling instead. But the need to REACT to confirmed loss is a hard requirement; the mechanism is a policy.",
      "testable_assertion": "Confirming a Parcel as Lost must produce a ParcelLostConfirmed domain event containing the Shipment reference, Parcel tracking number, and last known location."
    },
    {
      "id": "BR-11",
      "rule": "Parcels removed from a Shipment after creation (e.g., cancelled before pickup) must not be physically deleted. They must be marked as Cancelled with a reason, preserving the original Shipment composition for audit.",
      "invariant": true,
      "invariant_justification": "Deleting a parcel from a shipment destroys the record of what was originally ordered vs what was fulfilled. This is required for billing reconciliation, fraud detection, and dispute resolution.",
      "testable_assertion": "A cancelled Parcel remains in the Shipment's parcel list with status Cancelled. The Shipment's parcel count at creation is always recoverable."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A Shipment with 5 Parcels all in Created state",
      "when": "3 Parcels transition to Delivered and 2 remain In Transit",
      "then": "The Shipment derived status is PARTIALLY_DELIVERED and a PartialDelivery domain event is emitted"
    },
    {
      "id": "AC-2",
      "given": "A Shipment with 5 Parcels where 4 are Delivered",
      "when": "The 5th Parcel is confirmed as Lost",
      "then": "The Shipment derived status remains PARTIALLY_DELIVERED (not all delivered, mixed terminal states) and a ParcelLostConfirmed event is emitted"
    },
    {
      "id": "AC-3",
      "given": "A Shipment with 5 Parcels all Delivered",
      "when": "All 5 Parcels have reached Delivered with valid proof-of-delivery",
      "then": "The Shipment derived status is DELIVERED and a ShipmentFullyDelivered event is emitted"
    },
    {
      "id": "AC-4",
      "given": "A Parcel in Delivered state with proof-of-delivery recorded",
      "when": "A customer creates a Dispute referencing that Parcel's tracking number claiming non-receipt",
      "then": "The Dispute is created and linked to the specific Parcel. The Parcel status does NOT change until investigation concludes. The Shipment status remains unchanged during investigation."
    },
    {
      "id": "AC-5",
      "given": "A Parcel in Out for Delivery state",
      "when": "Delivery fails and a DeliveryFailed event is recorded with a reason code",
      "then": "The Parcel transitions to Delivery Failed state. The Shipment recalculates its derived status. The failed attempt is appended to the Parcel's immutable event history."
    },
    {
      "id": "AC-6",
      "given": "A Parcel currently in Delivered state",
      "when": "An API call attempts to transition it back to In Transit",
      "then": "The transition is rejected with a domain error. The Parcel state and event history remain unchanged."
    },
    {
      "id": "AC-7",
      "given": "A Shipment with 3 Parcels where 1 is Delivered, 1 is Lost, and 1 is Returned to Sender",
      "when": "The Shipment status is derived",
      "then": "The Shipment status is PARTIALLY_DELIVERED because at least one parcel was successfully delivered but not all."
    },
    {
      "id": "AC-8",
      "given": "An existing Shipment created under the old single-tracking model",
      "when": "The system is queried for that Shipment's parcels",
      "then": "The legacy Shipment is represented as a Shipment with exactly one Parcel whose tracking number matches the original Shipment tracking number. No data is lost in migration."
    },
    {
      "id": "AC-9",
      "given": "A new Shipment is being created",
      "when": "The request specifies 0 parcels",
      "then": "The creation is rejected with a validation error: a Shipment must contain at least one Parcel."
    },
    {
      "id": "AC-10",
      "given": "A Shipment with 5 Parcels where all 5 are Lost or Returned (none Delivered)",
      "when": "The Shipment status is derived",
      "then": "The Shipment status is FAILED — all parcels reached terminal states but none were successfully delivered."
    }
  ],

  "edge_cases": [
    {
      "scenario": "All parcels in a Shipment are Lost",
      "expected_behavior": "Shipment status is FAILED, not DELIVERED or PARTIALLY_DELIVERED. A ShipmentFailed domain event is emitted. This is distinct from partial delivery — the customer received nothing."
    },
    {
      "scenario": "A Parcel is marked Delivered but the customer disputes it immediately (within seconds)",
      "expected_behavior": "The Delivered status and proof-of-delivery remain on record. A Dispute is created referencing the Parcel. Investigation proceeds using the recorded proof-of-delivery data. The Parcel does NOT revert to a pre-delivery state during investigation."
    },
    {
      "scenario": "Two Parcels in the same Shipment are delivered to different addresses (split shipment)",
      "expected_behavior": "Each Parcel tracks its own delivery location. The Shipment is PARTIALLY_DELIVERED or DELIVERED based on all parcels regardless of delivery address. Proof-of-delivery for each parcel reflects its actual delivery location."
    },
    {
      "scenario": "A Parcel is damaged in transit and a replacement Parcel is created",
      "expected_behavior": "The original Parcel transitions to Damaged (terminal). A new Parcel is created within the same Shipment (or a linked replacement Shipment — see escalation). The Shipment status accounts for the replacement Parcel's lifecycle, not the damaged one."
    },
    {
      "scenario": "Network partition: two tracking events arrive out of order (e.g., Delivered event arrives before Out for Delivery event)",
      "expected_behavior": "Events must be applied in logical order based on the state machine, not arrival order. If Delivered arrives first, the Out for Delivery event is either reconciled as a preceding step or flagged as an anomaly. The Parcel must not end up in an inconsistent state."
    },
    {
      "scenario": "Customer disputes partial receipt: claims 2 of 5 parcels not received, but all 5 show Delivered",
      "expected_behavior": "Customer creates a Dispute referencing the 2 specific Parcel tracking numbers. The Shipment status remains DELIVERED during investigation. Each disputed Parcel's proof-of-delivery is reviewed independently."
    },
    {
      "scenario": "Legacy migration: a shipment with one tracking number and no parcel concept",
      "expected_behavior": "Migrated as a Shipment containing a single Parcel. The Parcel inherits the original tracking number and all historical tracking events. No behavioral change for single-parcel shipments."
    },
    {
      "scenario": "Parcel is in Delivery Failed state after maximum delivery attempts",
      "expected_behavior": "The system must define what happens after max attempts. Likely transitions to Returned to Sender or requires manual intervention. This is an ambiguity — see escalations."
    }
  ],

  "business_impact": {
    "financial": "Parcel-level tracking enables accurate partial delivery billing (charge only for delivered parcels), reduces blanket refunds on partially-delivered shipments, and provides evidence for insurance claims on individual lost/damaged parcels. The current all-or-nothing model likely over-refunds when only some parcels fail.",
    "operational": "Operations teams gain granular visibility to triage individual parcel exceptions without investigating entire shipments. Carrier performance can be measured per-parcel. However, the refactor significantly increases tracking event volume (N events per shipment instead of 1) and requires changes to every system that reads shipment status.",
    "user": "Customers see accurate, real-time status per parcel instead of a misleading single status for the whole shipment. 'Your shipment is in transit' when 3 of 5 parcels are already delivered is a poor experience. Parcel-level tracking enables precise delivery notifications and targeted dispute filing.",
    "risk": "Migration risk is HIGH — every existing shipment must be backfilled with parcel records. Any system reading shipment status (notifications, billing, analytics, carrier integrations) must be updated to handle the new derived-status model. A phased rollout is strongly recommended.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Improved tracking visibility and more precise dispute resolution. Must adapt to seeing multiple tracking numbers per order." },
      { "group": "Customer Support", "impact": "Can investigate at parcel level. Must be trained on new status model and dispute workflow. Tooling must be updated." },
      { "group": "Operations / Dispatch", "impact": "Granular exception handling per parcel. Increased event volume to monitor. Dashboard and alerting changes required." },
      { "group": "Carrier Partners", "impact": "Must provide per-parcel tracking updates. Integration contracts may need renegotiation if carriers currently report at shipment level." },
      { "group": "Finance / Billing", "impact": "Partial delivery enables per-parcel billing and partial refunds. Billing logic must be refactored from shipment-level to parcel-level." },
      { "group": "Engineering", "impact": "Significant refactor: new Parcel entity, state machine, event sourcing, migration scripts, API changes. Every consumer of Shipment status is affected." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The core domain model (Shipment as aggregate of Parcels, parcel-level state machine, derived shipment status) is well-understood and standard in logistics. However, several operational workflows are not specified: dispute resolution outcomes, replacement parcel handling, maximum delivery attempt policies, and the exact Lost detection mechanism. These ambiguities affect acceptance criteria completeness.",
    "high_confidence_areas": [
      "Parcel as independently trackable entity with its own lifecycle",
      "Shipment status derived from parcel states — never set independently",
      "Forward-only state machine for parcels with defined exception branches",
      "Immutable event history per parcel for audit and dispute resolution",
      "Disputes must reference specific parcels, not just the shipment",
      "Legacy migration strategy: one shipment → one parcel"
    ],
    "low_confidence_areas": [
      "Dispute resolution outcomes — what terminal states can a dispute produce? Can a Delivered parcel be reclassified?",
      "Replacement parcel handling — new parcel in same shipment, or a linked replacement shipment?",
      "Maximum delivery attempts before escalation — how many, and what is the escalation path?",
      "Lost detection trigger — time-based threshold, manual declaration, or carrier signal?",
      "SLA calculation changes — how do partial deliveries affect SLA compliance metrics?",
      "Out-of-order event reconciliation strategy — reorder by timestamp or apply compensation events?"
    ],
    "assumptions": [
      "The system will use event sourcing or at minimum an append-only event log per parcel for tracking history",
      "Carriers can provide parcel-level tracking events (not just shipment-level)",
      "The Shipment remains the customer-facing unit; parcels are visible but the shipment reference is the primary identifier for customers",
      "Cancelled parcels are treated as a terminal state but excluded from delivery percentage calculations"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Dispute resolution outcomes are undefined. When a customer disputes a Delivered parcel and investigation confirms the customer is correct (parcel not actually received), what happens? Does the Parcel state change from Delivered to a new state (e.g., DeliveryDisputed, Lost)? Or does it remain Delivered with a dispute annotation? This affects the Shipment derived status and has financial implications (refund triggers).",
      "affected_stakeholders": ["Customers", "Customer Support", "Finance / Billing"],
      "options": [
        "Parcel state reverts to a new post-investigation state (e.g., DeliveryRevoked) which changes Shipment derived status",
        "Parcel remains Delivered but a Dispute Resolution record overrides billing/refund logic without changing tracking state",
        "Parcel transitions to Lost (confirmed) after investigation, treated the same as carrier-reported loss"
      ],
      "recommendation": "Option B — keep tracking state immutable (Delivered stays Delivered as it reflects what the carrier reported) but let dispute resolution drive financial outcomes separately. This preserves audit integrity while enabling correct billing. The two concerns (physical tracking vs financial settlement) should be decoupled."
    },
    {
      "type": "ambiguity",
      "description": "Replacement parcel handling is unspecified. When a Parcel is confirmed Lost or Damaged and the business decides to reship, is the replacement Parcel added to the original Shipment or does it create a new linked Shipment? This affects how the customer sees their order, how billing works, and how delivery completion is calculated.",
      "affected_stakeholders": ["Customers", "Operations / Dispatch", "Finance / Billing"],
      "options": [
        "Add replacement Parcel to the original Shipment with a link to the original Parcel it replaces",
        "Create a new Shipment linked to the original, containing only the replacement Parcel(s)",
        "Support both models depending on business context (e.g., same-warehouse reship vs cross-warehouse)"
      ],
      "recommendation": "Option B — a replacement Shipment linked to the original. This keeps the original Shipment's parcel composition stable (important for audit and dispute history), avoids reopening a Shipment that may be in a terminal derived state, and simplifies the state machine."
    },
    {
      "type": "ambiguity",
      "description": "The trigger mechanism for declaring a Parcel as Lost is unspecified. Is it time-based (no tracking update for X days), carrier-reported, manually declared by operations, or some combination? The answer determines whether 'Lost' is a suspected vs confirmed state, and whether there should be two states (Suspected Lost → Confirmed Lost) or one.",
      "affected_stakeholders": ["Operations / Dispatch", "Customers", "Carrier Partners"],
      "options": [
        "Single Lost state triggered by carrier signal or manual declaration only",
        "Two-phase: Suspected Lost (time-based, auto-triggered) → Confirmed Lost (after investigation)",
        "Carrier-reported only — the system never independently declares loss"
      ],
      "recommendation": "Option B — a two-phase approach. Suspected Lost triggers investigation (and proactive customer communication), Confirmed Lost triggers financial resolution. This matches industry standard practice where most 'lost' parcels reappear within 48-72 hours."
    }
  ],

  "rejection_reasons": []
}

